def _participant_duration(price_rule_model, participant):
    nights = participant.actual_nights or participant.booked_nights or 0
    if nights > 7:
        return "2w"
    return "1w"


def _participant_role(price_rule_model, participant):
    if participant.is_companion:
        return "companion"
    return "participant"


def backfill_overnight_categories(apps, schema_editor):
    Camp = apps.get_model("billing", "Camp")
    OvernightCategory = apps.get_model("billing", "OvernightCategory")
