    category_labels = {
        ("participant", "1w"): "Teilnehmer 1 Woche",
        ("participant", "2w"): "Teilnehmer 2 Wochen",
        ("companion", "1w"): "Begleitperson 1 Woche",
        ("companion", "2w"): "Begleitperson 2 Wochen",
    }

    for camp in Camp.objects.all():
        categories = {}

        for rule in PriceRule.objects.filter(camp=camp, kind="camp_flat"):
            key = (rule.camp_flat_role, rule.camp_flat_duration)
            label = category_labels.get(key, "Bestand")
            category, _ = OvernightCategory.objects.get_or_create(camp=camp, name=label)
            categories[key] = category
            if not rule.overnight_category_id:
                rule.overnight_category = category
                rule.save(update_fields=["overnight_category"])

        fallback_category, _ = OvernightCategory.objects.get_or_create(
            camp=camp,
            name="Bestand",
            defaults={"description": "Automatisch aus vorhandenen Daten erzeugt."},
        )

        for participant in Participant.objects.filter(camp=camp, overnight_category__isnull=True):
            key = (_participant_role(PriceRule, participant), _participant_duration(PriceRule, participant))
            participant.overnight_category = categories.get(key, fallback_category)
            participant.save(update_fields=["overnight_category"])


